+    ///           try b.write(".x = 1, .y = 2");
+    ///       }
+    ///   }.emit, {});
+    ///
+    /// Generates: .{ .x = 1, .y = 2 }
+    pub fn withAnonStruct(self: *ZigBuilder, body_fn: anytype, context: anytype) !void {
+        try self.write(".{ ");
